/**
 * MMS Operational Constraints Tables (v2.1)
 *
 * Critical tables for operational requirements and constraints:
 * - Service demand: Minimum train availability (HARD constraint)
 * - Route utilization profiles: Mileage projection accuracy
 * - Unavailability events: CM/incident tracking (Maximo integration)
 * - Train-route compatibility: Technical constraints
 *
 * @see specs/003-database-schema.md Sections 3.2.1 - 3.2.4
 */

import { relations, sql } from 'drizzle-orm';
import {
  boolean,
  check,
  date,
  decimal,
  index,
  integer,
  pgTable,
  text,
  timestamp,
  uniqueIndex,
  uuid,
  varchar,
} from 'drizzle-orm/pg-core';
import { fleets, routes, trains } from './core-fleet';
import {
  confidenceLevelEnum,
  constraintTypeEnum,
  dayTypeEnum,
  fitnessStatusEnum,
  unavailabilityStatusEnum,
  unavailabilityTypeEnum,
} from './enums';
import { users } from './users';

/**
 * Service Demand - Minimum train availability requirements
 *
 * This is a HARD CONSTRAINT for the optimizer - it cannot schedule
 * maintenance that would violate availability targets.
 *
 * Service demand varies by:
 * - Fleet (different fleets serve different lines)
 * - Day type (weekday vs. weekend vs. holiday)
 * - Time of day (peak AM/PM vs. midday vs. evening)
 */
export const serviceDemand = pgTable(
  'service_demand',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    fleetId: uuid('fleet_id')
      .notNull()
      .references(() => fleets.id),
    effectiveDate: date('effective_date').notNull(),
    dayType: dayTypeEnum('day_type').notNull(),

    // Minimum availability requirements
    minTrainsRequired: integer('min_trains_required').notNull(),
    peakAmRequirement: integer('peak_am_requirement'), // 6:00-9:00
    middayRequirement: integer('midday_requirement'), // 9:00-16:00
    peakPmRequirement: integer('peak_pm_requirement'), // 16:00-19:00
    eveningRequirement: integer('evening_requirement'), // 19:00-23:00
    standbyBuffer: integer('standby_buffer').default(2), // Additional contingency

    // Metadata
    source: varchar('source', { length: 50 }), // 'OPERATIONS', 'CONTRACT', 'MANUAL'
    notes: text('notes'),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
    createdBy: uuid('created_by').references(() => users.id),
  },
  (table) => [
    uniqueIndex('idx_service_demand_unique').on(table.fleetId, table.effectiveDate, table.dayType),
    index('idx_service_demand_fleet').on(table.fleetId, table.effectiveDate),
    index('idx_service_demand_lookup').on(table.fleetId, table.dayType, table.effectiveDate),
  ]
);

/**
 * Route Utilization Profiles - Expected daily mileage by route
 *
 * Enables accurate long-term mileage projections. Without route-specific
 * profiles, projections use fleet-wide averages which can be off by
 * 60,000+ km over a 12-year contract period.
 *
 * Key fields:
 * - weekday_km, saturday_km, sunday_km: Daily mileage by day type
 * - seasonal multipliers: Adjust for holiday periods
 * - confidence: Data quality indicator
 */
export const routeUtilizationProfiles = pgTable(
  'route_utilization_profiles',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    routeId: uuid('route_id')
      .notNull()
      .references(() => routes.id),
    effectiveDate: date('effective_date').notNull().default(sql`CURRENT_DATE`),

    // Daily mileage by day type (km)
    weekdayKm: integer('weekday_km').notNull(),
    saturdayKm: integer('saturday_km'),
    sundayKm: integer('sunday_km'),
    holidayKm: integer('holiday_km'),

    // Seasonal adjustments (e.g., 1.15 for CNY peak)
    peakSeasonMultiplier: decimal('peak_season_multiplier', { precision: 3, scale: 2 }).default(
      '1.0'
    ),
    offPeakMultiplier: decimal('off_peak_multiplier', { precision: 3, scale: 2 }).default('1.0'),

    // Service characteristics
    serviceHoursPerDay: decimal('service_hours_per_day', { precision: 4, scale: 1 }),
    roundTripKm: decimal('round_trip_km', { precision: 6, scale: 2 }),
    tripsPerDay: integer('trips_per_day'),

    // Metadata
    source: varchar('source', { length: 50 }), // 'MEASURED', 'ESTIMATED', 'CONTRACT'
    confidence: confidenceLevelEnum('confidence').default('MEDIUM'),
    notes: text('notes'),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    uniqueIndex('idx_route_util_unique').on(table.routeId, table.effectiveDate),
    index('idx_route_util_route').on(table.routeId, table.effectiveDate),
  ]
);

/**
 * Unavailability Events - Trains out of service
 *
 * CRITICAL integration point with Maximo CMMS. Tracks trains that cannot
 * be scheduled due to corrective maintenance, incidents, or other factors.
 *
 * Key behaviors:
 * - When an event is created with status='ACTIVE', the train's fitness_status
 *   is automatically updated via trigger
 * - Events with restriction_level='GROUNDED' block both run assignment and PM
 * - Events with restriction_level='RESTRICTED' may allow limited operations
 *
 * Maximo integration:
 * - source_system='MAXIMO' for CM work orders
 * - external_reference holds the Maximo WO number (e.g., 'WO-2026-001234')
 * - external_status mirrors Maximo status (WAPPR, INPRG, COMP, etc.)
 */
export const unavailabilityEvents = pgTable(
  'unavailability_events',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    trainId: uuid('train_id')
      .notNull()
      .references(() => trains.id),

    // Event classification
    eventType: unavailabilityTypeEnum('event_type').notNull(),
    status: unavailabilityStatusEnum('status').notNull().default('ACTIVE'),
    restrictionLevel: fitnessStatusEnum('restriction_level').notNull(), // 'RESTRICTED' or 'GROUNDED'

    // Timing
    reportedAt: timestamp('reported_at', { withTimezone: true }).notNull().defaultNow(),
    estimatedRepairHours: integer('estimated_repair_hours'),
    estimatedReturnDate: date('estimated_return_date'),
    actualReturnDate: date('actual_return_date'),

    // External system linkage (Maximo integration)
    sourceSystem: varchar('source_system', { length: 30 }), // 'MAXIMO', 'OCC', 'MANUAL'
    externalReference: varchar('external_reference', { length: 50 }), // Maximo WO number
    externalStatus: varchar('external_status', { length: 30 }), // Maximo status

    // Description
    description: text('description'),
    failureCode: varchar('failure_code', { length: 30 }), // Standard failure classification
    affectedSystem: varchar('affected_system', { length: 50 }), // 'TRACTION', 'BRAKES', etc.

    // Scheduling impact flags
    blocksPmScheduling: boolean('blocks_pm_scheduling').default(true),
    blocksRunAssignment: boolean('blocks_run_assignment').default(true),

    // Resolution
    resolvedAt: timestamp('resolved_at', { withTimezone: true }),
    resolvedBy: uuid('resolved_by').references(() => users.id),
    resolutionNotes: text('resolution_notes'),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    // Constraint: Cannot have resolved data if status is ACTIVE
    check(
      'chk_resolved_status',
      sql`(${table.status} = 'ACTIVE' AND ${table.resolvedAt} IS NULL) OR (${table.status} = 'RESOLVED' AND ${table.resolvedAt} IS NOT NULL)`
    ),
    // Primary query: Find active unavailability for a train
    index('idx_unavailability_active').on(table.trainId, table.status),
    // Dashboard query: All active unavailability by estimated return
    index('idx_unavailability_return').on(table.estimatedReturnDate),
    // Maximo sync: Find by external reference
    index('idx_unavailability_external').on(table.sourceSystem, table.externalReference),
    // Audit: Find by type and date range
    index('idx_unavailability_audit').on(table.eventType, table.reportedAt),
  ]
);

/**
 * Train-Route Compatibility - Technical constraints
 *
 * Defines which trains can operate on which routes based on technical
 * constraints (signaling, gauge, power supply, etc.). Prevents the
 * optimizer from assigning incompatible trains to routes.
 *
 * Can be defined at:
 * - Fleet level (fleet_id): Applies to all trains in the fleet
 * - Train level (train_id): Overrides fleet-level for specific train
 *
 * Temporal support:
 * - effective_date/expiry_date allow temporary restrictions
 * - NULL expiry_date = permanent restriction
 */
export const trainRouteCompatibility = pgTable(
  'train_route_compatibility',
  {
    id: uuid('id').primaryKey().defaultRandom(),

    // Can be at train or fleet level (mutually exclusive)
    trainId: uuid('train_id').references(() => trains.id),
    fleetId: uuid('fleet_id').references(() => fleets.id),
    routeId: uuid('route_id')
      .notNull()
      .references(() => routes.id),

    // Compatibility determination
    isCompatible: boolean('is_compatible').notNull().default(true),
    constraintType: constraintTypeEnum('constraint_type'),
    restrictionReason: text('restriction_reason'),

    // Validity period (for temporary restrictions)
    effectiveDate: date('effective_date').default(sql`CURRENT_DATE`),
    expiryDate: date('expiry_date'), // NULL = permanent

    // Metadata
    verifiedBy: uuid('verified_by').references(() => users.id),
    verifiedAt: timestamp('verified_at', { withTimezone: true }),
    notes: text('notes'),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    // Must specify either train_id OR fleet_id, not both
    check(
      'chk_train_or_fleet',
      sql`(${table.trainId} IS NOT NULL AND ${table.fleetId} IS NULL) OR (${table.trainId} IS NULL AND ${table.fleetId} IS NOT NULL)`
    ),
    index('idx_compatibility_route').on(table.routeId, table.isCompatible),
    index('idx_compatibility_train').on(table.trainId, table.isCompatible),
    index('idx_compatibility_fleet').on(table.fleetId, table.isCompatible),
    index('idx_compatibility_active').on(table.effectiveDate, table.expiryDate),
  ]
);

