  pmTracking: many(componentPmTracking),
}));

export const componentInstallationsRelations = relations(componentInstallations, ({ one }) => ({
  component: one(trainComponents, {
    fields: [componentInstallations.componentId],
    references: [trainComponents.id],
  }),
  train: one(trains, {
    fields: [componentInstallations.trainId],
    references: [trains.id],
