  }),
  pmType: one(pmTypes, {
    fields: [componentPmTracking.pmTypeId],
    references: [pmTypes.id],
  }),
}));

/**
 * MMS Material Management Tables
 *
 * Inventory tracking and material reservations for PM scheduling.
 * Materials are a constraint for PM scheduling - PMs cannot proceed
 * without required blocking parts.
 *
 * Integration:
 * - Inventory snapshots come from Maximo/ERP daily
 * - Reservations are created when PMs are scheduled
 * - Soft reservations auto-expire if PM moves
 *
 * @see specs/003-database-schema.md Section 3.6
 */

import { relations } from 'drizzle-orm';
import {
  date,
  decimal,
  index,
  integer,
  pgTable,
  text,
  timestamp,
  uniqueIndex,
  uuid,
  varchar,
} from 'drizzle-orm/pg-core';
import { depots } from './core-fleet';
import { reservationTypeEnum } from './enums';
import { pmSchedule } from './pm-management';
import { users } from './users';

/**
 * Inventory Positions - Current stock levels
 *
 * Snapshot of inventory from ERP/Maximo system.
 * Updated daily via integration sync.
 *
 * Key fields:
 * - quantity_available: Calculated as on_hand - reserved
 * - reorder_point: Triggers replenishment when available drops below
 */
export const inventoryPositions = pgTable(
  'inventory_positions',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    depotId: uuid('depot_id')
      .notNull()
      .references(() => depots.id),
    partNumber: varchar('part_number', { length: 50 }).notNull(),
    partDescription: text('part_description'),

    // Quantities
    quantityOnHand: integer('quantity_on_hand').notNull().default(0),
    quantityReserved: integer('quantity_reserved').notNull().default(0),
    quantityOnOrder: integer('quantity_on_order').default(0),
    // quantity_available is calculated in queries: on_hand - reserved

    // Replenishment
    reorderPoint: integer('reorder_point'),
    reorderQuantity: integer('reorder_quantity'),
    nextDeliveryDate: date('next_delivery_date'),
    nextDeliveryQuantity: integer('next_delivery_quantity'),

    // Cost
    unitCost: decimal('unit_cost', { precision: 12, scale: 2 }),
    currency: varchar('currency', { length: 3 }).default('SGD'),

    // Sync tracking
    lastSyncAt: timestamp('last_sync_at', { withTimezone: true }),
    sourceSystem: varchar('source_system', { length: 50 }).default('MAXIMO'),

    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    uniqueIndex('idx_inventory_depot_part').on(table.depotId, table.partNumber),
    index('idx_inventory_depot').on(table.depotId),
    index('idx_inventory_part').on(table.partNumber),
  ]
);

/**
 * Material Reservations - Links inventory to PM schedules
 *
 * Two reservation types:
 * - SOFT: Tentative, auto-expires if PM moves (90-day soft constraint)
 * - HARD: Committed, parts allocated (14-day hard constraint)
 *
 * Constraint enforcement:
 * - BLOCKING parts with SOFT reservation: Warning, PM can proceed
 * - BLOCKING parts without reservation: PM cannot be scheduled
 */
export const materialReservations = pgTable(
  'material_reservations',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    pmScheduleId: uuid('pm_schedule_id')
      .notNull()
      .references(() => pmSchedule.id, { onDelete: 'cascade' }),
    inventoryPositionId: uuid('inventory_position_id')
      .notNull()
      .references(() => inventoryPositions.id),
    partNumber: varchar('part_number', { length: 50 }).notNull(),

    quantityReserved: integer('quantity_reserved').notNull(),
    reservationType: reservationTypeEnum('reservation_type').default('SOFT'),

    reservedAt: timestamp('reserved_at', { withTimezone: true }).defaultNow(),
    reservedBy: uuid('reserved_by').references(() => users.id),
    expiresAt: timestamp('expires_at', { withTimezone: true }), // SOFT reservations auto-expire

    // Fulfillment
    fulfilledAt: timestamp('fulfilled_at', { withTimezone: true }),
    fulfilledQuantity: integer('fulfilled_quantity'),
  },
  (table) => [
    uniqueIndex('idx_reservations_pm_part').on(table.pmScheduleId, table.partNumber),
    index('idx_reservations_pm').on(table.pmScheduleId),
    index('idx_reservations_inventory').on(table.inventoryPositionId),
    index('idx_reservations_expiring').on(table.expiresAt),
  ]
);

// ============================================================================
// Relations
// ============================================================================

export const inventoryPositionsRelations = relations(inventoryPositions, ({ one, many }) => ({
  depot: one(depots, {
    fields: [inventoryPositions.depotId],
    references: [depots.id],
  }),
  reservations: many(materialReservations),
}));

export const materialReservationsRelations = relations(materialReservations, ({ one }) => ({
  pmScheduleRecord: one(pmSchedule, {
    fields: [materialReservations.pmScheduleId],
    references: [pmSchedule.id],
  }),
  inventoryPosition: one(inventoryPositions, {
    fields: [materialReservations.inventoryPositionId],
    references: [inventoryPositions.id],
  }),
  reservedByUser: one(users, {
    fields: [materialReservations.reservedBy],
    references: [users.id],
  }),
}));

/**
 * MMS Man-hour Planning Tables
 *
 * Workforce capacity planning and workload leveling.
 * Used to balance maintenance workload across time periods
 * and prevent overloading/underutilization of depot resources.
 *
 * Leveling strategies (priority order):
 * 1. ADVANCE_PM (1.1x cost, LOW risk)
 * 2. DEFER_PM (1.05x cost, LOW risk)
 * 3. ADD_OVERTIME (1.5x cost, NO risk)
 * 4. CROSS_DEPOT (1.3x cost, MEDIUM risk)
 * 5. ADD_CONTRACTOR (2.0x cost, MEDIUM risk)
 * 6. MANUAL_REVIEW (flagged for high unresolvable overload)
 *
 * @see specs/003-database-schema.md Section 3.7
 */

import { relations } from 'drizzle-orm';
import {
  date,
  decimal,
  index,
  integer,
  pgTable,
  text,
  timestamp,
  uniqueIndex,
  uuid,
  varchar,
} from 'drizzle-orm/pg-core';
import { depots } from './core-fleet';
import { adjustmentStatusEnum } from './enums';
import { users } from './users';

/**
 * Man-hour Capacity - Resource availability by depot
 *
 * Defines the workforce capacity for each depot by shift type.
 * Includes utilization targets to guide leveling decisions.
 */
export const manhourCapacity = pgTable(
  'manhour_capacity',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    depotId: uuid('depot_id')
      .notNull()
      .references(() => depots.id),
    effectiveFrom: date('effective_from').notNull(),
    effectiveTo: date('effective_to'),

    // Base capacity per shift type (hours per week)
    dayShiftHours: decimal('day_shift_hours', { precision: 8, scale: 2 }).notNull(),
    nightShiftHours: decimal('night_shift_hours', { precision: 8, scale: 2 }).default('0'),
    weekendHours: decimal('weekend_hours', { precision: 8, scale: 2 }).default('0'),

    // Staff counts
    techniciansDay: integer('technicians_day').notNull(),
    techniciansNight: integer('technicians_night').default(0),
    specialists: integer('specialists').default(0),

    // Utilization targets
    maxOvertimePct: decimal('max_overtime_pct', { precision: 5, scale: 2 }).default('20.0'),
    minUtilizationPct: decimal('min_utilization_pct', { precision: 5, scale: 2 }).default('70.0'),
    targetUtilizationPct: decimal('target_utilization_pct', { precision: 5, scale: 2 }).default(
      '85.0'
    ),

    notes: text('notes'),
    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    uniqueIndex('idx_manhour_cap_depot_date').on(table.depotId, table.effectiveFrom),
    index('idx_manhour_cap_depot').on(table.depotId),
  ]
);

/**
 * Man-hour Projections - Generated workload forecasts
 *
 * Created by the leveling engine to show required vs. available hours.
 * Used for capacity planning and overload detection.
 */
export const manhourProjections = pgTable(
  'manhour_projections',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    projectionRunId: uuid('projection_run_id').notNull(),
    depotId: uuid('depot_id')
      .notNull()
      .references(() => depots.id),

    periodStart: date('period_start').notNull(),
    periodEnd: date('period_end').notNull(),
    granularity: varchar('granularity', { length: 20 }).notNull(), // 'WEEKLY', 'MONTHLY'

    // Required hours breakdown
    requiredPmHours: decimal('required_pm_hours', { precision: 10, scale: 2 }).notNull(),
    requiredCorrectiveHours: decimal('required_corrective_hours', {
      precision: 10,
      scale: 2,
    }).default('0'),
    requiredOverhaulHours: decimal('required_overhaul_hours', {
      precision: 10,
      scale: 2,
    }).default('0'),
    requiredTotalHours: decimal('required_total_hours', { precision: 10, scale: 2 }).notNull(),

    // Available hours
    availableRegularHours: decimal('available_regular_hours', {
      precision: 10,
      scale: 2,
    }).notNull(),
    availableOvertimeHours: decimal('available_overtime_hours', {
      precision: 10,
      scale: 2,
    }).notNull(),
    availableTotalHours: decimal('available_total_hours', { precision: 10, scale: 2 }).notNull(),

    // Computed metrics (calculated in application layer)
    // variance_hours = available_total - required_total
    // utilization_pct = (required_total / available_total) * 100
    // is_overloaded = required_total > available_total
    // is_underutilized = required_total < available_total * 0.7

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    index('idx_manhour_proj_depot').on(table.depotId, table.periodStart),
    index('idx_manhour_proj_run').on(table.projectionRunId),
  ]
);

/**
 * Man-hour Adjustments - Proposed workload changes
 *
 * Leveling engine suggestions to balance workload.
 * Requires approval workflow before being applied.
 */
export const manhourAdjustments = pgTable(
  'manhour_adjustments',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    projectionId: uuid('projection_id')
      .notNull()
      .references(() => manhourProjections.id),

    adjustmentType: varchar('adjustment_type', { length: 50 }).notNull(),
    // 'ADD_OVERTIME', 'DEFER_PM', 'ADVANCE_PM', 'CROSS_DEPOT', 'ADD_CONTRACTOR'

    sourcePeriodStart: date('source_period_start'),
    sourcePeriodEnd: date('source_period_end'),
    targetPeriodStart: date('target_period_start'),
    targetPeriodEnd: date('target_period_end'),
    hoursAdjusted: decimal('hours_adjusted', { precision: 10, scale: 2 }).notNull(),

    affectedPmIds: text('affected_pm_ids').array().default([]),
    affectedTrainIds: text('affected_train_ids').array().default([]),

    // Impact assessment
    costImpact: decimal('cost_impact', { precision: 12, scale: 2 }),
    riskImpact: varchar('risk_impact', { length: 20 }), // 'NONE', 'LOW', 'MEDIUM', 'HIGH'
    riskDescription: text('risk_description'),

    // Workflow
    status: adjustmentStatusEnum('status').default('PROPOSED'),
    proposedBy: uuid('proposed_by').references(() => users.id),
    proposedAt: timestamp('proposed_at', { withTimezone: true }).defaultNow(),
    approvedBy: uuid('approved_by').references(() => users.id),
    approvedAt: timestamp('approved_at', { withTimezone: true }),
    rejectionReason: text('rejection_reason'),

    // Explanation
    reason: text('reason').notNull(),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    index('idx_manhour_adj_projection').on(table.projectionId),
    index('idx_manhour_adj_status').on(table.status),
  ]
);

// ============================================================================
// Relations
// ============================================================================

export const manhourCapacityRelations = relations(manhourCapacity, ({ one }) => ({
  depot: one(depots, {
    fields: [manhourCapacity.depotId],
    references: [depots.id],
  }),
}));

export const manhourProjectionsRelations = relations(manhourProjections, ({ one, many }) => ({
  depot: one(depots, {
    fields: [manhourProjections.depotId],
    references: [depots.id],
  }),
  adjustments: many(manhourAdjustments),
}));

export const manhourAdjustmentsRelations = relations(manhourAdjustments, ({ one }) => ({
  projection: one(manhourProjections, {
    fields: [manhourAdjustments.projectionId],
    references: [manhourProjections.id],
  }),
  proposedByUser: one(users, {
    fields: [manhourAdjustments.proposedBy],
    references: [users.id],
    relationName: 'proposedBy',
  }),
  approvedByUser: one(users, {
    fields: [manhourAdjustments.approvedBy],
    references: [users.id],
    relationName: 'approvedBy',
  }),
}));

/**
 * MMS Baseline & Drift Tables
 *
 * Plan stability through immutable baseline snapshots and drift monitoring.
 *
 * Baseline/Drift Architecture:
 * - Baselines are published snapshots of the PM schedule and mileage projections
 * - Drift analysis compares current state to baseline
 * - When drift exceeds thresholds, requires_replan flag is set
 *
 * Drift thresholds:
 * - Mileage: ±5.0%
 * - Schedule: ±14 days
 * - Fleet: ≥5 trains requiring replan
 *
 * @see specs/003-database-schema.md Section 3.8
 */

import { relations } from 'drizzle-orm';
import {
  boolean,
  date,
  decimal,
  index,
  integer,
  pgTable,
  text,
  timestamp,
  uniqueIndex,
  uuid,
  varchar,
} from 'drizzle-orm/pg-core';
import { depots, trains } from './core-fleet';
import { baselineStatusEnum } from './enums';
import { pmTypes } from './pm-management';
import { users } from './users';

/**
 * Plan Baselines - Immutable schedule snapshots
 *
 * A baseline captures the state of PM scheduling and mileage projections
 * at a point in time. Published baselines become the reference for drift analysis.
 *
 * Status lifecycle:
 * DRAFT -> PUBLISHED -> SUPERSEDED (when new baseline published)
 */
export const planBaselines = pgTable(
  'plan_baselines',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    name: varchar('name', { length: 100 }).notNull(),
    description: text('description'),
    version: varchar('version', { length: 20 }).notNull(), // 'v3.2'

    baselineDate: date('baseline_date').notNull(), // "As of" date
    horizonEnd: date('horizon_end').notNull(), // How far into future

    // Workflow
    status: baselineStatusEnum('status').default('DRAFT'),
    createdBy: uuid('created_by')
      .notNull()
      .references(() => users.id),
    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),

    publishedBy: uuid('published_by').references(() => users.id),
    publishedAt: timestamp('published_at', { withTimezone: true }),

    supersededBy: uuid('superseded_by'),
    supersededAt: timestamp('superseded_at', { withTimezone: true }),

    // Metrics at baseline time
    fleetCount: integer('fleet_count'),
    totalPmScheduled: integer('total_pm_scheduled'),
    totalManhourProjected: decimal('total_manhour_projected', { precision: 12, scale: 2 }),
  },
  (table) => [
    index('idx_baselines_status').on(table.status),
    index('idx_baselines_date').on(table.baselineDate),
  ]
);

/**
 * Baseline PM Schedule - Snapshot of scheduled maintenance
 *
 * Immutable copy of PM schedule at baseline time.
 * Used for drift comparison.
 */
export const baselinePmSchedule = pgTable(
  'baseline_pm_schedule',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    baselineId: uuid('baseline_id')
      .notNull()
      .references(() => planBaselines.id, { onDelete: 'cascade' }),

    trainId: uuid('train_id')
      .notNull()
      .references(() => trains.id),
    pmTypeId: uuid('pm_type_id')
      .notNull()
      .references(() => pmTypes.id),
    projectedDate: date('projected_date').notNull(),
    projectedMileageKm: integer('projected_mileage_km'),

    assignedDepotId: uuid('assigned_depot_id').references(() => depots.id),
    assignedHours: decimal('assigned_hours', { precision: 6, scale: 2 }),
  },
  (table) => [
    uniqueIndex('idx_baseline_pm_unique').on(
      table.baselineId,
      table.trainId,
      table.pmTypeId,
      table.projectedDate
    ),
    index('idx_baseline_pm_baseline').on(table.baselineId),
    index('idx_baseline_pm_train').on(table.trainId, table.projectedDate),
  ]
);

/**
 * Baseline Mileage Projection - Snapshot of mileage forecasts
 *
 * Immutable copy of mileage projections at baseline time.
 * Used for drift comparison.
 */
export const baselineMileageProjection = pgTable(
  'baseline_mileage_projection',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    baselineId: uuid('baseline_id')
      .notNull()
      .references(() => planBaselines.id, { onDelete: 'cascade' }),

    trainId: uuid('train_id')
      .notNull()
      .references(() => trains.id),
    projectionDate: date('projection_date').notNull(),
    projectedCumulativeKm: integer('projected_cumulative_km').notNull(),
    dailyRateKm: integer('daily_rate_km'), // Assumed daily accrual rate
  },
  (table) => [
    uniqueIndex('idx_baseline_mileage_unique').on(
      table.baselineId,
      table.trainId,
      table.projectionDate
    ),
    index('idx_baseline_mileage').on(table.baselineId, table.trainId),
  ]
);

/**
 * Drift Analysis - Comparison results
 *
 * Generated by drift monitor (nightly job).
 * Compares current state to baseline and flags trains requiring replan.
 */
export const driftAnalysis = pgTable(
  'drift_analysis',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    baselineId: uuid('baseline_id')
      .notNull()
      .references(() => planBaselines.id),
    analysisDate: date('analysis_date').notNull(),

    trainId: uuid('train_id')
      .notNull()
      .references(() => trains.id),

    // Mileage drift
    baselineProjectedKm: integer('baseline_projected_km').notNull(),
    actualKm: integer('actual_km').notNull(),
    // mileage_drift_km = actual - baseline (calculated in queries)
    mileageDriftPct: decimal('mileage_drift_pct', { precision: 5, scale: 2 }),

    // Schedule drift (days)
    avgPmDriftDays: decimal('avg_pm_drift_days', { precision: 5, scale: 1 }),
    maxPmDriftDays: integer('max_pm_drift_days'),

    // Threshold breach
    requiresReplan: boolean('requires_replan').default(false),
    replanReason: text('replan_reason'),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    uniqueIndex('idx_drift_unique').on(table.baselineId, table.trainId, table.analysisDate),
    index('idx_drift_baseline').on(table.baselineId, table.analysisDate),
    index('idx_drift_replan').on(table.requiresReplan, table.analysisDate),
  ]
);

// ============================================================================
// Relations
// ============================================================================

export const planBaselinesRelations = relations(planBaselines, ({ one, many }) => ({
  createdByUser: one(users, {
    fields: [planBaselines.createdBy],
    references: [users.id],
    relationName: 'createdBy',
  }),
  publishedByUser: one(users, {
    fields: [planBaselines.publishedBy],
    references: [users.id],
    relationName: 'publishedBy',
  }),
  supersededByBaseline: one(planBaselines, {
    fields: [planBaselines.supersededBy],
    references: [planBaselines.id],
    relationName: 'supersedes',
  }),
  pmScheduleSnapshots: many(baselinePmSchedule),
  mileageProjections: many(baselineMileageProjection),
  driftAnalyses: many(driftAnalysis),
}));

export const baselinePmScheduleRelations = relations(baselinePmSchedule, ({ one }) => ({
  baseline: one(planBaselines, {
    fields: [baselinePmSchedule.baselineId],
    references: [planBaselines.id],
  }),
  train: one(trains, {
    fields: [baselinePmSchedule.trainId],
    references: [trains.id],
  }),
  pmType: one(pmTypes, {
    fields: [baselinePmSchedule.pmTypeId],
    references: [pmTypes.id],
  }),
  assignedDepot: one(depots, {
    fields: [baselinePmSchedule.assignedDepotId],
    references: [depots.id],
  }),
}));

export const baselineMileageProjectionRelations = relations(
  baselineMileageProjection,
  ({ one }) => ({
    baseline: one(planBaselines, {
      fields: [baselineMileageProjection.baselineId],
      references: [planBaselines.id],
    }),
    train: one(trains, {
      fields: [baselineMileageProjection.trainId],
      references: [trains.id],
    }),
  })
);

export const driftAnalysisRelations = relations(driftAnalysis, ({ one }) => ({
  baseline: one(planBaselines, {
    fields: [driftAnalysis.baselineId],
    references: [planBaselines.id],
  }),
  train: one(trains, {
    fields: [driftAnalysis.trainId],
    references: [trains.id],
  }),
}));

/**
 * MMS Scenario Management Tables
 *
 * Event-sourced what-if analysis for PM schedule planning.
 *
 * Scenarios allow planners to:
 * - Fork from a baseline or another scenario
 * - Make changes (PM_MOVE, PM_ADD, PM_REMOVE, etc.)
 * - Compare scenarios side-by-side
 * - Promote winning scenario to new baseline
 *
 * Event sourcing: Changes are stored as deltas, not mutations.
 * This allows replaying history and comparing states.
 *
 * @see specs/003-database-schema.md Section 3.9
 */

import { relations, sql } from 'drizzle-orm';
import {
  date,
  decimal,
  index,
  integer,
  jsonb,
  pgTable,
  text,
  timestamp,
  uniqueIndex,
  uuid,
  varchar,
} from 'drizzle-orm/pg-core';
import { scenarioStatusEnum } from './enums';
import { planBaselines } from './baseline-drift';
import { users } from './users';

/**
 * Scenarios - What-if analysis containers
 *
 * Each scenario forks from a baseline or another scenario.
 * Changes are tracked as deltas for full history replay.
 *
 * Auto-expiration: Inactive scenarios expire after 30 days.
 */
export const scenarios = pgTable(
  'scenarios',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    name: varchar('name', { length: 100 }).notNull(),
    description: text('description'),

    // Fork point
    forkedFromBaselineId: uuid('forked_from_baseline_id').references(() => planBaselines.id),
    forkedFromScenarioId: uuid('forked_from_scenario_id'),
    forkedAt: timestamp('forked_at', { withTimezone: true }).defaultNow(),

    // Metadata
    status: scenarioStatusEnum('status').default('ACTIVE'),
    createdBy: uuid('created_by')
      .notNull()
      .references(() => users.id),
    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),

    // Expiration (auto-expire after 30 days of inactivity)
    lastModifiedAt: timestamp('last_modified_at', { withTimezone: true }).defaultNow(),
    expiresAt: timestamp('expires_at', { withTimezone: true }).default(
      sql`NOW() + INTERVAL '30 days'`
    ),

    // Promotion
    promotedToBaselineId: uuid('promoted_to_baseline_id').references(() => planBaselines.id),
    promotedAt: timestamp('promoted_at', { withTimezone: true }),
    promotedBy: uuid('promoted_by').references(() => users.id),
  },
  (table) => [
    index('idx_scenarios_status').on(table.status),
    index('idx_scenarios_user').on(table.createdBy, table.status),
    index('idx_scenarios_expiring').on(table.expiresAt),
  ]
);

/**
 * Scenario Deltas - Event-sourced changes
 *
 * Each delta represents a change made to the scenario.
 * Changes are applied in sequence_num order.
 *
 * Delta types:
 * - PM_MOVE: Reschedule PM to new date
 * - PM_ADD: Insert new PM
 * - PM_REMOVE: Delete PM
 * - CAPACITY_CHANGE: Modify man-hour capacity
 * - TRAIN_STATUS_CHANGE: Update train fitness/restrictions
 */
export const scenarioDeltas = pgTable(
  'scenario_deltas',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    scenarioId: uuid('scenario_id')
      .notNull()
      .references(() => scenarios.id, { onDelete: 'cascade' }),
    sequenceNum: integer('sequence_num').notNull(),

    deltaType: varchar('delta_type', { length: 50 }).notNull(),
    // 'PM_MOVE', 'PM_ADD', 'PM_REMOVE', 'CAPACITY_CHANGE', 'TRAIN_STATUS_CHANGE'

    // Reference to affected entity
    entityType: varchar('entity_type', { length: 50 }).notNull(), // 'pm_schedule', 'manhour_capacity', etc.
    entityId: uuid('entity_id').notNull(),

    // Change details
    oldValues: jsonb('old_values'),
    newValues: jsonb('new_values'),

    // Explanation
    changeReason: text('change_reason'),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    createdBy: uuid('created_by').references(() => users.id),
  },
  (table) => [
    uniqueIndex('idx_scenario_deltas_unique').on(table.scenarioId, table.sequenceNum),
    index('idx_scenario_deltas_scenario').on(table.scenarioId, table.sequenceNum),
  ]
);

/**
 * Scenario Comparisons - Pre-computed comparison results
 *
 * Materialized comparison between two scenarios or a scenario and baseline.
 * Created on-demand when user requests comparison.
 */
export const scenarioComparisons = pgTable(
  'scenario_comparisons',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    scenarioAId: uuid('scenario_a_id')
      .notNull()
      .references(() => scenarios.id),
    scenarioBId: uuid('scenario_b_id').references(() => scenarios.id), // NULL = compare to baseline
    baselineId: uuid('baseline_id').references(() => planBaselines.id),

    comparisonDate: date('comparison_date').notNull(),

    // Summary metrics
    pmCountDelta: integer('pm_count_delta'),
    totalHoursDelta: decimal('total_hours_delta', { precision: 10, scale: 2 }),
    totalCostDelta: decimal('total_cost_delta', { precision: 12, scale: 2 }),
    overloadedWeeksDelta: integer('overloaded_weeks_delta'),

    // Detailed differences (JSON)
    pmDifferences: jsonb('pm_differences'),
    manhourDifferences: jsonb('manhour_differences'),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    index('idx_scenario_comp_a').on(table.scenarioAId),
    index('idx_scenario_comp_b').on(table.scenarioBId),
  ]
);

// ============================================================================
// Relations
// ============================================================================

export const scenariosRelations = relations(scenarios, ({ one, many }) => ({
  forkedFromBaseline: one(planBaselines, {
    fields: [scenarios.forkedFromBaselineId],
    references: [planBaselines.id],
    relationName: 'forkedFromBaseline',
  }),
  forkedFromScenario: one(scenarios, {
    fields: [scenarios.forkedFromScenarioId],
    references: [scenarios.id],
    relationName: 'forkedFrom',
  }),
  createdByUser: one(users, {
    fields: [scenarios.createdBy],
    references: [users.id],
    relationName: 'createdBy',
  }),
  promotedToBaseline: one(planBaselines, {
    fields: [scenarios.promotedToBaselineId],
    references: [planBaselines.id],
    relationName: 'promotedTo',
  }),
  promotedByUser: one(users, {
    fields: [scenarios.promotedBy],
    references: [users.id],
    relationName: 'promotedBy',
  }),
  deltas: many(scenarioDeltas),
}));

export const scenarioDeltasRelations = relations(scenarioDeltas, ({ one }) => ({
  scenario: one(scenarios, {
    fields: [scenarioDeltas.scenarioId],
    references: [scenarios.id],
  }),
  createdByUser: one(users, {
    fields: [scenarioDeltas.createdBy],
    references: [users.id],
  }),
}));

export const scenarioComparisonsRelations = relations(scenarioComparisons, ({ one }) => ({
  scenarioA: one(scenarios, {
    fields: [scenarioComparisons.scenarioAId],
    references: [scenarios.id],
    relationName: 'scenarioA',
  }),
  scenarioB: one(scenarios, {
    fields: [scenarioComparisons.scenarioBId],
    references: [scenarios.id],
    relationName: 'scenarioB',
  }),
  baseline: one(planBaselines, {
    fields: [scenarioComparisons.baselineId],
    references: [planBaselines.id],
  }),
}));

/**
 * MMS Costing Tables
 *
 * Financial tracking for maintenance operations.
 * Used for TCO (Total Cost of Ownership) projections over the 12-year contract.
 *
 * Cost components:
 * - Labor: Hourly rates with shift/weekend/holiday multipliers
 * - Materials: Part costs with effective dating
 * - Overhead: 18% of direct costs (standard industry rate)
 *
 * TCO projection parameters:
 * - Inflation: 3% annually
 * - Discount rate: 5% for NPV calculations
 *
 * @see specs/003-database-schema.md Section 3.10
 */

import { relations } from 'drizzle-orm';
import {
  date,
  decimal,
  index,
  integer,
  pgTable,
  timestamp,
  uniqueIndex,
  uuid,
  varchar,
} from 'drizzle-orm/pg-core';
import { depots } from './core-fleet';

/**
 * Labor Rates - Hourly costs for maintenance work
 *
 * Rates can be depot-specific or global (depot_id = NULL).
 * Includes multipliers for overtime, weekend, and holiday work.
 */
export const laborRates = pgTable(
  'labor_rates',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    depotId: uuid('depot_id').references(() => depots.id), // NULL = global default
    effectiveFrom: date('effective_from').notNull(),
    effectiveTo: date('effective_to'),

    // Rate types
    regularHourlyRate: decimal('regular_hourly_rate', { precision: 10, scale: 2 }).notNull(),
    overtimeMultiplier: decimal('overtime_multiplier', { precision: 3, scale: 2 }).default('1.5'),
    weekendMultiplier: decimal('weekend_multiplier', { precision: 3, scale: 2 }).default('2.0'),
    holidayMultiplier: decimal('holiday_multiplier', { precision: 3, scale: 2 }).default('2.5'),

    // Shop rate (fully loaded with overhead, benefits, etc.)
    shopRateHourly: decimal('shop_rate_hourly', { precision: 10, scale: 2 }),

    currency: varchar('currency', { length: 3 }).default('SGD'),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    uniqueIndex('idx_labor_rates_depot_date').on(table.depotId, table.effectiveFrom),
    index('idx_labor_rates_depot').on(table.depotId),
  ]
);

/**
 * Material Costs - Part pricing history
 *
 * Historical part prices for accurate cost calculation.
 * Effective dating allows for price changes over time.
 */
export const materialCosts = pgTable(
  'material_costs',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    partNumber: varchar('part_number', { length: 50 }).notNull(),
    effectiveFrom: date('effective_from').notNull(),
    effectiveTo: date('effective_to'),

    unitCost: decimal('unit_cost', { precision: 12, scale: 2 }).notNull(),
    currency: varchar('currency', { length: 3 }).default('SGD'),
    supplier: varchar('supplier', { length: 100 }),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    uniqueIndex('idx_material_costs_part_date').on(table.partNumber, table.effectiveFrom),
    index('idx_material_costs_part').on(table.partNumber),
  ]
);

/**
 * Cost Baselines - Budget vs. Actual tracking
 *
 * Annual cost tracking for variance analysis.
 * Used for financial reporting and forecasting.
 */
export const costBaselines = pgTable(
  'cost_baselines',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    fiscalYear: integer('fiscal_year').notNull(),
    depotId: uuid('depot_id').references(() => depots.id),

    // Budget
    budgetLaborHours: decimal('budget_labor_hours', { precision: 12, scale: 2 }),
    budgetLaborCost: decimal('budget_labor_cost', { precision: 14, scale: 2 }),
    budgetMaterialCost: decimal('budget_material_cost', { precision: 14, scale: 2 }),
    budgetTotal: decimal('budget_total', { precision: 14, scale: 2 }),

    // Actuals (updated monthly)
    actualLaborHours: decimal('actual_labor_hours', { precision: 12, scale: 2 }),
    actualLaborCost: decimal('actual_labor_cost', { precision: 14, scale: 2 }),
    actualMaterialCost: decimal('actual_material_cost', { precision: 14, scale: 2 }),
    actualTotal: decimal('actual_total', { precision: 14, scale: 2 }),

    // variance_pct calculated in queries: ((actual - budget) / budget) * 100

    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    uniqueIndex('idx_cost_baselines_year_depot').on(table.fiscalYear, table.depotId),
    index('idx_cost_baselines_year').on(table.fiscalYear),
  ]
);

// ============================================================================
// Relations
// ============================================================================

export const laborRatesRelations = relations(laborRates, ({ one }) => ({
  depot: one(depots, {
    fields: [laborRates.depotId],
    references: [depots.id],
  }),
}));

export const costBaselinesRelations = relations(costBaselines, ({ one }) => ({
  depot: one(depots, {
    fields: [costBaselines.depotId],
    references: [depots.id],
  }),
}));

/**
 * MMS Audit & History Tables
 *
 * Immutable audit trail for compliance with 12-year government contract.
 * All PM schedule changes and significant actions are logged.
 *
 * Key requirements:
 * - Full attribution (who, when, why)
 * - Before/after values for all changes
 * - Optimizer decisions must include explanation traces
 * - Compliance flags for safety-critical changes
 *
 * @see specs/003-database-schema.md Section 3.11
 */

import { relations } from 'drizzle-orm';
import {
  date,
  decimal,
  index,
  inet,
  jsonb,
  pgTable,
  text,
  timestamp,
  uuid,
  varchar,
} from 'drizzle-orm/pg-core';
import { auditActionEnum, changeSourceEnum, pmChangeTypeEnum, pmStatusEnum } from './enums';
import { pmSchedule } from './pm-management';
import { users } from './users';

/**
 * PM Schedule History - Detailed change tracking for PM records
 *
 * Every change to a PM schedule is logged here.
 * Includes optimizer context when changes are suggested by the optimizer.
 *
 * Change types:
 * - CREATED: New PM scheduled
 * - DATE_CHANGED: Target date moved
 * - STATUS_CHANGED: Status transition
 * - TRACK_ASSIGNED: Track allocation changed
 * - LOCKED/UNLOCKED: Lock state changed
 * - COMPLETED/CANCELLED/DEFERRED: Terminal states
 */
export const pmScheduleHistory = pgTable(
  'pm_schedule_history',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    pmScheduleId: uuid('pm_schedule_id')
      .notNull()
      .references(() => pmSchedule.id),

    changeType: pmChangeTypeEnum('change_type').notNull(),

    // Previous values
    oldTargetDate: date('old_target_date'),
    oldStatus: pmStatusEnum('old_status'),
    oldAssignedTrackId: uuid('old_assigned_track_id'),
    oldAssignedHours: decimal('old_assigned_hours', { precision: 6, scale: 2 }),

    // New values
    newTargetDate: date('new_target_date'),
    newStatus: pmStatusEnum('new_status'),
    newAssignedTrackId: uuid('new_assigned_track_id'),
    newAssignedHours: decimal('new_assigned_hours', { precision: 6, scale: 2 }),

    // Attribution
    changedBy: uuid('changed_by')
      .notNull()
      .references(() => users.id),
    changedAt: timestamp('changed_at', { withTimezone: true }).defaultNow(),
    changeReason: text('change_reason'),
    changeSource: changeSourceEnum('change_source').default('USER'),

    // Optimizer context (if change was suggested by optimizer)
    optimizerRequestId: uuid('optimizer_request_id'),
    optimizerExplanation: jsonb('optimizer_explanation'),
  },
  (table) => [
    index('idx_pm_history_schedule').on(table.pmScheduleId, table.changedAt),
    index('idx_pm_history_date').on(table.changedAt),
    index('idx_pm_history_user').on(table.changedBy, table.changedAt),
  ]
);

/**
 * Audit Log - General system audit trail
 *
 * Captures all significant actions across the system.
 * Used for compliance reporting and investigation.
 *
 * Actions:
 * - CREATE, UPDATE, DELETE: Data modifications
 * - APPROVE, REJECT: Workflow decisions
 * - PUBLISH: Baseline publication
 */
export const auditLog = pgTable(
  'audit_log',
  {
    id: uuid('id').primaryKey().defaultRandom(),

    // What
    entityType: varchar('entity_type', { length: 50 }).notNull(), // 'pm_schedule', 'baseline', etc.
    entityId: uuid('entity_id').notNull(),
    action: auditActionEnum('action').notNull(),

    // Who
    userId: uuid('user_id')
      .notNull()
      .references(() => users.id),
    userEmail: varchar('user_email', { length: 255 }),
    userIpAddress: inet('user_ip_address'),

    // When
    occurredAt: timestamp('occurred_at', { withTimezone: true }).defaultNow(),

    // Details
    oldValues: jsonb('old_values'),
    newValues: jsonb('new_values'),
    metadata: jsonb('metadata'), // Additional context

    // Compliance
    complianceFlags: text('compliance_flags').array(), // ['SAFETY_CRITICAL', 'FINANCIAL']
  },
  (table) => [
    index('idx_audit_entity').on(table.entityType, table.entityId, table.occurredAt),
    index('idx_audit_user').on(table.userId, table.occurredAt),
    index('idx_audit_date').on(table.occurredAt),
  ]
);

// ============================================================================
// Relations
// ============================================================================

export const pmScheduleHistoryRelations = relations(pmScheduleHistory, ({ one }) => ({
  pmScheduleRecord: one(pmSchedule, {
    fields: [pmScheduleHistory.pmScheduleId],
    references: [pmSchedule.id],
  }),
  changedByUser: one(users, {
    fields: [pmScheduleHistory.changedBy],
    references: [users.id],
  }),
}));

export const auditLogRelations = relations(auditLog, ({ one }) => ({
  user: one(users, {
    fields: [auditLog.userId],
    references: [users.id],
  }),
}));

/**
 * MMS Users & Authentication Tables
 *
 * Access control and session management for the MMS system.
 * Supports RBAC (Role-Based Access Control) with fine-grained permissions.
 *
 * @see specs/003-database-schema.md Section 3.12
 */

import { relations } from 'drizzle-orm';
import {
  boolean,
  index,
  integer,
  jsonb,
  pgTable,
  text,
  timestamp,
  uuid,
  varchar,
} from 'drizzle-orm/pg-core';
import { depots } from './core-fleet';

/**
 * Users - System users
 *
 * Includes planners, depot managers, system admins, and technicians.
 * Each user can have certifications (for technician constraint matching).
 */
export const users = pgTable(
  'users',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    email: varchar('email', { length: 255 }).notNull().unique(),
    passwordHash: varchar('password_hash', { length: 255 }).notNull(),

    firstName: varchar('first_name', { length: 100 }),
    lastName: varchar('last_name', { length: 100 }),
    displayName: varchar('display_name', { length: 200 }),

    // Assignment
    primaryDepotId: uuid('primary_depot_id').references(() => depots.id),
    roleIds: text('role_ids').array().notNull().default([]),

    // Certifications (for technician constraint matching)
    certifications: text('certifications').array(),

    // Status
    isActive: boolean('is_active').default(true),
    lastLoginAt: timestamp('last_login_at', { withTimezone: true }),
    failedLoginAttempts: integer('failed_login_attempts').default(0),
    lockedUntil: timestamp('locked_until', { withTimezone: true }),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    index('idx_users_email').on(table.email),
    index('idx_users_depot').on(table.primaryDepotId),
  ]
);

/**
 * Roles - Permission groups
 *
 * Standard roles include:
 * - PLANNER: Can create/modify PM schedules
 * - DEPOT_MANAGER: Manages depot-specific operations
 * - SYSTEM_ADMIN: Full system access
 * - VIEWER: Read-only access
 *
 * Permissions are stored as JSONB for flexibility:
 * { "pm_schedule": ["read", "write"], "baseline": ["read"] }
 */
export const roles = pgTable('roles', {
  id: uuid('id').primaryKey().defaultRandom(),
  name: varchar('name', { length: 50 }).notNull().unique(),
  description: text('description'),
  permissions: jsonb('permissions').notNull(), // e.g., {"pm_schedule": ["read", "write"]}
  createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
});

/**
 * Sessions - User sessions
 *
 * Note: In production, sessions are typically stored in Redis for performance.
 * This table provides a fallback and audit trail.
 */
export const sessions = pgTable(
  'sessions',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    userId: uuid('user_id')
      .notNull()
      .references(() => users.id),
    tokenHash: varchar('token_hash', { length: 255 }).notNull(),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    expiresAt: timestamp('expires_at', { withTimezone: true }).notNull(),
    lastActivityAt: timestamp('last_activity_at', { withTimezone: true }).defaultNow(),

    ipAddress: varchar('ip_address', { length: 45 }), // IPv6 max length
    userAgent: text('user_agent'),
  },
  (table) => [index('idx_sessions_user').on(table.userId), index('idx_sessions_expiry').on(table.expiresAt)]
);

// ============================================================================
// Relations
// ============================================================================

export const usersRelations = relations(users, ({ one, many }) => ({
  primaryDepot: one(depots, {
    fields: [users.primaryDepotId],
    references: [depots.id],
  }),
  sessions: many(sessions),
}));

export const sessionsRelations = relations(sessions, ({ one }) => ({
  user: one(users, {
    fields: [sessions.userId],
    references: [users.id],
  }),
}));
